        body.put("messages", extractNonSystemMessages(request));
        body.put("system", extractSystemMessage(request));
        body.put("max_tokens", request.getMaxTokens() != null ? 
                request.getMaxTokens() : 4096);  // Claude必填
        // ...调用 + 转换
    }
}
